// P² Directory Submission Verification - sem fetch e sem variáveis de ambiente.
// Cole sua SUPABASE_SERVICE_ROLE_KEY abaixo, sem "Bearer".
const SUPABASE_URL = 'https://fljcywbqzzakwgzyguvl.supabase.co';
const SUPABASE_KEY = 'COLE_AQUI_SUA_SUPABASE_SERVICE_ROLE_KEY';

if (!SUPABASE_KEY || SUPABASE_KEY.includes('COLE_AQUI')) {
  throw new Error('Cole a SUPABASE_SERVICE_ROLE_KEY dentro deste nó Code antes de executar.');
}

const httpRequest = this.helpers.httpRequest.bind(this);
const input = $input.first().json || {};
const query = input.query || input.body || {};
const syncId = query.sync_id || query.syncId || null;
const locationId = query.location_id || query.locationId || null;
const limit = Math.min(Number(query.limit || 30), 100);

const headers = {
  apikey: SUPABASE_KEY,
  Authorization: `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json',
  Accept: 'application/json',
  Prefer: 'return=representation'
};

function enc(value) { return encodeURIComponent(String(value)); }
function onlyDigits(value) { return String(value || '').replace(/\D/g, ''); }
function cleanText(value) {
  return String(value || '')
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
}
function normalizeUrl(url) {
  if (!url) return null;
  const raw = String(url).trim();
  if (!raw) return null;
  return /^https?:\/\//i.test(raw) ? raw : `https://${raw}`;
}
function applyTemplate(template, data) {
  if (!template) return null;
  const replacements = {
    name: data.name || '',
    city: data.city || '',
    state: data.state || '',
    phone: onlyDigits(data.phone || ''),
    zip: onlyDigits(data.zip || ''),
    q: [data.name, data.city, data.state].filter(Boolean).join(' '),
  };
  let out = String(template);
  for (const [key, value] of Object.entries(replacements)) {
    out = out.replaceAll(`{${key}}`, encodeURIComponent(value));
  }
  return normalizeUrl(out);
}

async function supabaseRequest(path, options = {}) {
  const req = {
    method: options.method || 'GET',
    url: `${SUPABASE_URL}${path}`,
    headers: { ...headers, ...(options.headers || {}) },
    json: true,
    resolveWithFullResponse: true,
    simple: false,
  };
  if (options.body !== undefined) req.body = options.body;
  const response = await httpRequest(req);
  const statusCode = response.statusCode || response.status || 200;
  const body = response.body !== undefined ? response.body : response;
  if (statusCode >= 400) {
    throw new Error(`Supabase ${statusCode}: ${typeof body === 'string' ? body : JSON.stringify(body)}`);
  }
  return body;
}

async function getOne(path) {
  const rows = await supabaseRequest(path);
  return Array.isArray(rows) && rows.length ? rows[0] : null;
}

async function getHtml(url) {
  const startedAt = Date.now();
  const response = await httpRequest({
    method: 'GET',
    url,
    headers: {
      'User-Agent': 'Mozilla/5.0 P2LocalListingsVerifier/1.0',
      Accept: 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8'
    },
    resolveWithFullResponse: true,
    simple: false,
    timeout: 15000,
  });
  return {
    statusCode: response.statusCode || response.status || null,
    body: String(response.body || ''),
    durationMs: Date.now() - startedAt
  };
}

let filter = 'select=*&order=updated_at.desc';
if (syncId) filter += `&sync_id=eq.${enc(syncId)}`;
if (locationId) filter += `&location_id=eq.${enc(locationId)}`;
if (!syncId && !locationId) {
  filter += `&verification_status=in.(not_checked,pending_review,manual_check_required,error)&limit=${limit}`;
} else {
  filter += `&limit=${limit}`;
}

const submissions = await supabaseRequest(`/rest/v1/directory_submissions?${filter}`);
const results = [];

for (const sub of submissions || []) {
  const checkedAt = new Date().toISOString();
  const channelCode = sub.channel_code;
  let status = 'manual_check_required';
  let message = 'Sem URL verificável configurada. Conferência manual recomendada.';
  let profileUrl = sub.profile_url || null;
  let checkedUrl = null;
  let statusCode = null;
  let foundName = false;
  let foundPhone = false;
  let foundCity = false;

  const channel = await getOne(`/rest/v1/directory_channels?code=eq.${enc(channelCode)}&select=*`);
  const company = sub.company_id ? await getOne(`/rest/v1/companies?id=eq.${enc(sub.company_id)}&select=*`) : null;
  const location = sub.location_id ? await getOne(`/rest/v1/google_locations?id=eq.${enc(sub.location_id)}&select=*`) : null;

  const raw = typeof sub.raw_response === 'string' ? (() => { try { return JSON.parse(sub.raw_response); } catch { return {}; } })() : (sub.raw_response || {});
  const business = {
    name: company?.name || location?.name || raw.copyPayload?.['Nome da empresa'] || raw.copy_payload?.['Nome da empresa'] || '',
    phone: company?.phone || location?.phone_primary || raw.copyPayload?.Telefone || raw.copy_payload?.Telefone || '',
    city: company?.city || location?.address_city || raw.copyPayload?.Cidade || raw.copy_payload?.Cidade || '',
    state: company?.state || location?.address_state || raw.copyPayload?.Estado || raw.copy_payload?.Estado || '',
    zip: company?.postal_code || location?.address_postal_code || raw.copyPayload?.CEP || raw.copy_payload?.CEP || '',
  };

  if (profileUrl) {
    checkedUrl = normalizeUrl(profileUrl);
  } else if (channel?.verification_url_template) {
    checkedUrl = applyTemplate(channel.verification_url_template, business);
  } else if (channel?.search_url_template) {
    checkedUrl = applyTemplate(channel.search_url_template, business);
  }

  if (checkedUrl) {
    try {
      const page = await getHtml(checkedUrl);
      statusCode = page.statusCode;
      const html = cleanText(page.body);
      const businessName = cleanText(business.name);
      const businessCity = cleanText(business.city);
      const phoneDigits = onlyDigits(business.phone);
      const htmlDigits = onlyDigits(page.body);

      foundName = businessName ? html.includes(businessName) : false;
      foundCity = businessCity ? html.includes(businessCity) : false;
      foundPhone = phoneDigits && phoneDigits.length >= 8 ? htmlDigits.includes(phoneDigits.slice(-8)) : false;

      if (page.statusCode >= 200 && page.statusCode < 400 && (foundName || foundPhone)) {
        status = 'found_online';
        message = 'Perfil ou página com dados compatíveis encontrado online.';
        profileUrl = checkedUrl;
      } else if (page.statusCode === 401 || page.statusCode === 403 || page.statusCode === 429) {
        status = 'manual_check_required';
        message = `Diretório bloqueou verificação automática ou exige login/captcha. HTTP ${page.statusCode}.`;
      } else if (page.statusCode === 404 || page.statusCode === 410) {
        status = 'not_found';
        message = `URL verificada não existe ou foi removida. HTTP ${page.statusCode}.`;
      } else if (page.statusCode >= 200 && page.statusCode < 400) {
        status = 'data_mismatch';
        message = 'Página acessível, mas nome/telefone/cidade não bateram com os dados enviados.';
      } else {
        status = 'manual_check_required';
        message = `Resposta HTTP ${page.statusCode}. Conferir manualmente.`;
      }
    } catch (err) {
      status = 'error';
      message = err.message || 'Erro ao verificar URL.';
    }
  }

  await supabaseRequest(`/rest/v1/directory_submissions?id=eq.${enc(sub.id)}`, {
    method: 'PATCH',
    body: {
      verification_status: status,
      verification_message: message,
      verified_at: checkedAt,
      profile_url: profileUrl,
      updated_at: checkedAt,
    }
  });

  await supabaseRequest('/rest/v1/directory_submission_verification_logs', {
    method: 'POST',
    body: {
      submission_id: sub.id,
      sync_id: sub.sync_id,
      channel_code: channelCode,
      checked_url: checkedUrl,
      status,
      status_code: statusCode,
      found_name: foundName,
      found_phone: foundPhone,
      found_city: foundCity,
      profile_url: profileUrl,
      message,
      raw_response: { business, channel: channel || {}, previous_status: sub.verification_status || null },
      checked_at: checkedAt,
    }
  });

  results.push({ channel: channelCode, status, message, checkedUrl, profileUrl, statusCode, foundName, foundPhone, foundCity });
}

return [{
  json: {
    success: true,
    sync_id: syncId,
    location_id: locationId,
    checked: results.length,
    found_online: results.filter(r => r.status === 'found_online').length,
    manual_check_required: results.filter(r => r.status === 'manual_check_required').length,
    not_found: results.filter(r => r.status === 'not_found').length,
    data_mismatch: results.filter(r => r.status === 'data_mismatch').length,
    error: results.filter(r => r.status === 'error').length,
    timestamp: new Date().toISOString(),
    results
  }
}];
